meta.script:
// Script de redirección para GitHub Pages (SPA friendly)
(function() {
  var l = window.location;
  // Esta lógica toma la URL que dio error 404 y la convierte al formato con Hash (#)
  var path = l.pathname;
  var search = l.search;
  var hash = l.hash;

  // Redirigir a la raíz con el hash correspondiente
  var newUrl = l.protocol + '//' + l.hostname + (l.port ? ':' + l.port : '') + '/#' + path + search + hash;

  // Ejecutar la redirección
  window.location.replace(newUrl);
})();
